import{_ as a,c as i,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"插件介绍: 功能与风险 | Antigravity Auth","description":"学习 Antigravity Auth 插件的核心价值和风险提示。通过 Google OAuth 访问 Claude 和 Gemini 3 模型，支持多账户负载均衡。","frontmatter":{"title":"插件介绍: 功能与风险 | Antigravity Auth","sidebarTitle":"这个插件适合你吗","subtitle":"了解 Antigravity Auth 插件的核心价值","description":"学习 Antigravity Auth 插件的核心价值和风险提示。通过 Google OAuth 访问 Claude 和 Gemini 3 模型，支持多账户负载均衡。","tags":["入门","插件介绍","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"zh/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"zh/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),e={name:"zh/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function r(n,t,s,h,u,d){return o(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="了解-antigravity-auth-插件的核心价值" tabindex="-1">了解 Antigravity Auth 插件的核心价值 <a class="header-anchor" href="#了解-antigravity-auth-插件的核心价值" aria-label="Permalink to &quot;了解 Antigravity Auth 插件的核心价值&quot;">​</a></h1><p><strong>Antigravity Auth</strong> 是一个 OpenCode 插件，通过 Google OAuth 认证访问 Antigravity API。它让你用熟悉的 Google 账号就能调用 Claude Opus 4.5、Sonnet 4.5 和 Gemini 3 Pro/Flash 等高级模型，无需管理 API 密钥。插件还提供多账户负载均衡、双配额池和自动会话恢复等功能，适合需要高级模型和自动管理的用户。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>判断这个插件是否适合你的使用场景</li><li>了解插件支持哪些 AI 模型和核心功能</li><li>明确使用此插件的风险和注意事项</li><li>决定是否继续安装和配置</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>想要使用最先进的 AI 模型（如 Claude Opus 4.5、Gemini 3 Pro），但官方访问受限。寻找可靠的方式获取这些模型，同时希望：</p><ul><li>不需要手动管理多个 API 密钥</li><li>遇到速率限制时能自动切换账户</li><li>对话中断后能自动恢复，不丢失上下文</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>Antigravity Auth</strong> 是一个 OpenCode 插件，通过 <strong>Google OAuth 认证</strong> 访问 Google Antigravity API，让你用自己熟悉的 Google 账号就能调用高级 AI 模型。</p><p>它不是代理所有请求，而是<strong>拦截并转换</strong>你的模型调用请求，将其转发到 Antigravity API，再把响应转换回 OpenCode 可以识别的格式。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h2><h3 id="支持的模型" tabindex="-1">支持的模型 <a class="header-anchor" href="#支持的模型" aria-label="Permalink to &quot;支持的模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型系列</th><th>可用模型</th><th>特点</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5、Sonnet 4.5</td><td>支持扩展思考模式</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro、Flash</td><td>Google Search 集成、扩展思考</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">思考模式（Thinking）</p><p>Thinking 模型会在生成回答前先进行&quot;深度思考&quot;，展示推理过程。你可以配置思考预算，平衡质量和响应速度。</p></div><h3 id="多账户负载均衡" tabindex="-1">多账户负载均衡 <a class="header-anchor" href="#多账户负载均衡" aria-label="Permalink to &quot;多账户负载均衡&quot;">​</a></h3><ul><li><strong>最多支持 10 个 Google 账户</strong></li><li>遇到速率限制（429 错误）时自动切换到下一个账户</li><li>三种账户选择策略：sticky（固定）、round-robin（轮换）、hybrid（智能混合）</li></ul><h3 id="双配额系统" tabindex="-1">双配额系统 <a class="header-anchor" href="#双配额系统" aria-label="Permalink to &quot;双配额系统&quot;">​</a></h3><p>插件同时访问<strong>两个独立的配额池</strong>：</p><ol><li><strong>Antigravity 配额</strong>：来自 Google Antigravity API</li><li><strong>Gemini CLI 配额</strong>：来自 Google Gemini CLI</li></ol><p>当一个池限速时，插件会自动尝试另一个池，最大化配额利用率。</p><h3 id="自动会话恢复" tabindex="-1">自动会话恢复 <a class="header-anchor" href="#自动会话恢复" aria-label="Permalink to &quot;自动会话恢复&quot;">​</a></h3><ul><li>检测工具调用失败（如按 ESC 中断）</li><li>自动注入 synthetic tool_result，避免对话崩溃</li><li>支持自动发送 &quot;continue&quot; 继续对话</li></ul><h3 id="google-search-集成" tabindex="-1">Google Search 集成 <a class="header-anchor" href="#google-search-集成" aria-label="Permalink to &quot;Google Search 集成&quot;">​</a></h3><p>为 Gemini 模型启用网页搜索，提升事实准确性：</p><ul><li><strong>Auto 模式</strong>：模型根据需要决定是否搜索</li><li><strong>Always-on 模式</strong>：每次都搜索</li></ul><h2 id="什么时候用这个插件" tabindex="-1">什么时候用这个插件 <a class="header-anchor" href="#什么时候用这个插件" aria-label="Permalink to &quot;什么时候用这个插件&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">适合以下场景</p><ul><li>你有多个 Google 账号，希望提高总体配额</li><li>需要使用 Claude 或 Gemini 3 的 Thinking 模型</li><li>想要为 Gemini 模型启用 Google Search</li><li>不想手动管理 API 密钥，更习惯 OAuth 认证</li><li>经常遇到速率限制，希望自动切换账户</li></ul></div><div class="warning custom-block"><p class="custom-block-title">不适合以下场景</p><ul><li>你需要使用 Google 官方未公开的模型</li><li>你对 Google ToS 风险非常敏感（见下方风险提示）</li><li>你只需要基础的 Gemini 1.5 或 Claude 3 模型（官方接口更稳定）</li><li>你在 WSL、Docker 等环境中打开浏览器困难</li></ul></div><h2 id="⚠️-重要风险提示" tabindex="-1">⚠️ 重要风险提示 <a class="header-anchor" href="#⚠️-重要风险提示" aria-label="Permalink to &quot;⚠️ 重要风险提示&quot;">​</a></h2><p>使用此插件<strong>可能违反 Google 的服务条款</strong>。少量用户报告他们的 Google 账号被<strong>封禁</strong>或<strong>影子封禁</strong>（限制访问但不明确通知）。</p><h3 id="高风险场景" tabindex="-1">高风险场景 <a class="header-anchor" href="#高风险场景" aria-label="Permalink to &quot;高风险场景&quot;">​</a></h3><ul><li>🚨 <strong>全新的 Google 账号</strong>：被封禁概率极高</li><li>🚨 <strong>新开通 Pro/Ultra 订阅的账号</strong>：容易被标记并封禁</li></ul><h3 id="使用前请确认" tabindex="-1">使用前请确认 <a class="header-anchor" href="#使用前请确认" aria-label="Permalink to &quot;使用前请确认&quot;">​</a></h3><ul><li>这是一个<strong>非官方工具</strong>，Google 未认可</li><li>你的账号可能被暂停或永久封禁</li><li>你承担使用此插件的所有风险</li></ul><h3 id="建议" tabindex="-1">建议 <a class="header-anchor" href="#建议" aria-label="Permalink to &quot;建议&quot;">​</a></h3><ul><li>使用<strong>成熟的 Google 账号</strong>，而非为此插件创建新账号</li><li>避免使用与关键服务绑定的重要账号</li><li>如果账号被封禁，无法通过此插件申诉</li></ul><div class="danger custom-block"><p class="custom-block-title">账号安全</p><p>所有 OAuth 令牌都存储在本地 <code>~/.config/opencode/antigravity-accounts.json</code>，不会上传到任何服务器。但请确保你的电脑安全，防止令牌泄露。</p></div><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Antigravity Auth 是一个强大的 OpenCode 插件，让你通过 Google OAuth 访问 Claude 和 Gemini 3 高级模型。它提供多账户负载均衡、双配额池、自动会话恢复等功能，适合需要高级模型和自动管理的用户。</p><p>但请务必注意：<strong>使用此插件有封号风险</strong>。请使用非关键的 Google 账号，并了解相关风险后再继续安装。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../quick-install/">快速安装</a></strong>。</p><p>你会学到：</p><ul><li>5 分钟完成插件安装</li><li>添加第一个 Google 账户</li><li>验证安装成功</li></ul></blockquote>',42)])])}const p=a(e,[["render",r]]);export{c as __pageData,p as default};
